import{_ as e,o as t,c as s,a as o}from"./app-2a089349.js";const n={},i=o('<h1 id="stripe-faq-do-subscriptions-replace-or-merge-roles" tabindex="-1"><a class="header-anchor" href="#stripe-faq-do-subscriptions-replace-or-merge-roles" aria-hidden="true">#</a> Stripe FAQ - Do Subscriptions Replace or Merge Roles?</h1><p>When a subscription status changes in the Stripe Plan, it typically assigns a new role to a user in addition to their existing role. However, if you prefer to change roles instead of combining them, you can enable an option to do so. To enable this option, navigate to <strong>WP-Admin &gt; Ultimate Member &gt; Settings &gt; Extensions &gt; Stripe</strong>, and enable the <strong>&quot;Replace existing roles when a subscription status changes&quot;</strong> setting.</p><p>By default, when the status of a Stripe subscription changes, the extension combines the new role with any existing roles. This means that users will have both their old and new roles. If you enable the <strong>&quot;Replace existing roles when a subscription status changes</strong><strong>&quot;</strong> option, it will remove the existing roles and assign only the new role when a subscription status changes.</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65e4df4d8cb417537bd299b1/file-DB3S0WKUxw.png" alt=""></p><blockquote><p><strong>Note:</strong> This will replace all roles when &quot;replace existing roles&quot; is enabled/checked. If you&#39;re using an Administrator account, the role will not change. It&#39;s best to use a subscriber account as a test account.</p></blockquote>',5),a=[i];function r(c,l){return t(),s("div",null,a)}const p=e(n,[["render",r],["__file","1618-do-subscriptions-replace-or-merge-roles.html.vue"]]);export{p as default};
